import socket
import uasyncio as asyncio
import ujson

class WebSocketServer:
    def __init__(self, host='0.0.0.0', port=8765):
        self.host = host
        self.port = port
        self.server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server_socket.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        self.server_socket.bind((self.host, self.port))
        self.server_socket.listen(5)

    async def handle_client(self, client_socket):
        while True:
            try:
                data = await asyncio.wait_for(client_socket.recv(1024), timeout=1)
                if not data:
                    break
                message = ujson.loads(data.decode('utf-8'))
                if 'action' in message and message['action'] == 'turn_on':
                    # Handle turn on command
                    print("Turn On Command Received")
            except asyncio.TimeoutError:
                pass
        client_socket.close()

    async def run(self):
        while True:
            client_socket, addr = await self.server_socket.accept()
            print(f"Accepted connection from {addr}")
            asyncio.create_task(self.handle_client(client_socket))

if __name__ == "__main__":
    server = WebSocketServer()
    asyncio.run(server.run())